echo ">>> cmmbhsz1o0005mempvrlz3n0g"
python3 << PYEOF
import base64,gzip,subprocess
b64=""
sql=gzip.decompress(base64.b64decode(b64)).decode("utf-8")
p=subprocess.Popen(["docker","exec","-i","w12b7gmnfug9fdi7kxdabrge","psql","-U","postgres","-d","postgres"],stdin=subprocess.PIPE,stdout=subprocess.PIPE,stderr=subprocess.PIPE)
o,e=p.communicate(input=sql.encode("utf-8"))
out=o.decode("utf-8",errors="replace")
[print(l) for l in out.splitlines() if "verificacao" in l.lower() or "row" in l.lower() or "ERROR" in l or ("UPDATE 0" in l)]
if e and e.strip(): print("ERRO:",e.decode("utf-8",errors="replace")[:400])
PYEOF

